好的，这里是一个简单的 C++ 参考代码示例，用于对一个 `vector<uint8_t>` 类型的数据进行霍夫曼编码：

```c++
#include <iostream>
#include <vector>
#include <queue>
#include <unordered_map>
#include <bitset>

using namespace std;

// 定义霍夫曼编码树节点
struct HuffmanTreeNode {
    uint8_t pixel;
    int frequency;
    HuffmanTreeNode* left;
    HuffmanTreeNode* right;

    HuffmanTreeNode(uint8_t pixel, int frequency) {
        this->pixel = pixel;
        this->frequency = frequency;
        this->left = nullptr;
        this->right = nullptr;
    }

    // 用于比较节点的频率
    struct Compare {
        bool operator()(const HuffmanTreeNode* lhs, const HuffmanTreeNode* rhs) const {
            return lhs->frequency > rhs->frequency;
        }
    };
};

// 生成霍夫曼编码树
HuffmanTreeNode* GenerateHuffmanTree(vector<uint8_t>& input_data) {
    // 统计每个像素的频率
    unordered_map<uint8_t, int> freq_map;
    for (uint8_t pixel : input_data) {
        freq_map[pixel]++;
    }

    // 将每个像素的频率转化为霍夫曼树节点
    priority_queue<HuffmanTreeNode*, vector<HuffmanTreeNode*>, HuffmanTreeNode::Compare> pq;
    for (auto& entry : freq_map) {
        pq.push(new HuffmanTreeNode(entry.first, entry.second));
    }

    // 构建霍夫曼编码树
    while (pq.size() > 1) {
        HuffmanTreeNode* left = pq.top(); pq.pop();
        HuffmanTreeNode* right = pq.top(); pq.pop();
        HuffmanTreeNode* parent = new HuffmanTreeNode(0, left->frequency + right->frequency);
        parent->left = left;
        parent->right = right;
        pq.push(parent);
    }
    return pq.top();
}

// 构建编码表
void BuildEncodingTable(HuffmanTreeNode* root, string code, unordered_map<uint8_t, string>& encoding_table) {
    if (!root) return;
    if (!root->left && !root->right) {
        encoding_table[root->pixel] = code;
    }
    if (root->left) {
        BuildEncodingTable(root->left, code + "0", encoding_table);
    }
    if (root->right) {
        BuildEncodingTable(root->right, code + "1", encoding_table);
    }
}

// 对输入数据进行霍夫曼编码
void HuffmanEncode(vector<uint8_t>& input_data, unordered_map<uint8_t, string>& encoding_table, string& encoded_data) {
    for (uint8_t pixel : input_data) {
        encoded_data += encoding_table[pixel];
    }
}

// 输出二进制编码
void OutputBinaryString(string encoded_data) {
    bitset<8> byte;
    for (int i = 0; i < encoded_data.size(); i++) {
        byte.set(7 - (i % 8), encoded_data[i] - '0');
        if (i % 8 == 7) {
            cout << byte.to_ulong() << " ";
        }
    }
    if (encoded_data.size() % 8 != 0) {
        byte <<= (8 - encoded_data.size() % 8);
        cout << byte.to_ulong() << endl;
    }
}

int main() {
    vector<uint8_t> input_data = { 0, 1, 2, 2, 1, 0, 0, 2, 0 };
    // 生成霍夫曼编码树
    HuffmanTreeNode* root = GenerateHuffmanTree(input_data);

    // 构建编码表
    unordered_map<uint8_t, string> encoding_table;
    BuildEncodingTable(root, "", encoding_table);

    // 对输入数据进行霍夫曼编码
    string encoded_data;
    HuffmanEncode(input_data, encoding_table, encoded_data);

    // 输出二进制编码
    OutputBinaryString(encoded_data);

    return 0;
}
```

在这个示例中，我们使用一个优先队列来构建霍夫曼编码树，并使用递归的方法生成编码表，最后使用二进制字符串输出编码结果，其中，输出的二进制字符串可以根据需求进一步保存、传输或存储。

