以下是一个示例子类的构造函数，使用初始化列表调用基类构造函数，并向其传递参数：

```c++
#include <iostream>

class Base {
public:
    Base(int i) {
        std::cout << "Base constructor with i = " << i << std::endl;
    }
};

class Derived : public Base {
public:
    Derived(int i, int j) : Base(i) {
        std::cout << "Derived constructor with j = " << j << std::endl;
    }
};

int main() {
    Derived d(1, 2);   // Output: Base constructor with i = 1, Derived constructor with j = 2
    return 0;
}
```

